// OAuth 1.0a signature generation for X API v2
const crypto = require('crypto');

const body = $input.first().json.body;
const tweetText = body.body; // post body text
const documentId = body.documentId;
const brand = body.brand;

// X API credentials from environment
const apiKey = $env.X_API_KEY;
const apiSecret = $env.X_API_SECRET;
const accessToken = $env.X_ACCESS_TOKEN;
const accessTokenSecret = $env.X_ACCESS_TOKEN_SECRET;

if (!apiKey || !apiSecret || !accessToken || !accessTokenSecret) {
  throw new Error('Missing X API credentials in n8n environment');
}

function percentEncode(str) {
  return encodeURIComponent(str).replace(/[!'()*]/g, c => `%${c.charCodeAt(0).toString(16).toUpperCase()}`);
}

const method = 'POST';
const url = 'https://api.twitter.com/2/tweets';

const oauthParams = {
  oauth_consumer_key: apiKey,
  oauth_nonce: crypto.randomBytes(16).toString('hex'),
  oauth_signature_method: 'HMAC-SHA1',
  oauth_timestamp: Math.floor(Date.now() / 1000).toString(),
  oauth_token: accessToken,
  oauth_version: '1.0',
};

// Generate signature
const sorted = Object.keys(oauthParams).sort()
  .map(k => `${percentEncode(k)}=${percentEncode(oauthParams[k])}`)
  .join('&');
const baseString = `${method}&${percentEncode(url)}&${percentEncode(sorted)}`;
const signingKey = `${percentEncode(apiSecret)}&${percentEncode(accessTokenSecret)}`;
const signature = crypto.createHmac('sha1', signingKey).update(baseString).digest('base64');
oauthParams['oauth_signature'] = signature;

const headerParts = Object.keys(oauthParams).sort()
  .map(k => `${percentEncode(k)}="${percentEncode(oauthParams[k])}"`)
  .join(', ');
const authHeader = `OAuth ${headerParts}`;

return {
  json: {
    documentId,
    brand,
    tweetText,
    authHeader,
    url,
  }
};
